diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index c112fae35181..7798be903872 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -8640,6 +8640,27 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
         return replaceOperand(I, 0, X);
       if (Instruction *NV = FoldOpIntoSelect(I, cast<SelectInst>(LHSI)))
         return NV;
+      // fcmp oeq (fcmp ord X, 0.0 ? X : 0.0), C --> fcmp oeq X, C
+      // fcmp une (fcmp ord X, 0.0 ? X : 0.0), C --> fcmp une X, C
+      // This is valid because if X is NaN, fcmp oeq X, C is false,
+      // and fcmp oeq 0.0, C is also false (when C != 0.0).
+      // If C == 0.0, the transformation is not valid since:
+      //   fcmp oeq (NaN ? X : 0.0), 0.0 = fcmp oeq 0.0, 0.0 = true
+      //   fcmp oeq NaN, 0.0 = false
+      if (FCmpInst::isEquality(Pred)) {
+        if (auto *SI = dyn_cast<SelectInst>(LHSI)) {
+          if (auto *CondFCmp = dyn_cast<FCmpInst>(SI->getCondition())) {
+            if (CondFCmp->getPredicate() == FCmpInst::FCMP_ORD &&
+                match(CondFCmp->getOperand(1), m_PosZeroFP()) &&
+                match(SI->getTrueValue(), m_Value(X)) &&
+                CondFCmp->getOperand(0) == X &&
+                match(SI->getFalseValue(), m_PosZeroFP()) &&
+                !match(RHSC, m_PosZeroFP())) {
+              return new FCmpInst(Pred, X, RHSC, "", &I);
+            }
+          }
+        }
+      }
       break;
     case Instruction::FSub:
       if (LHSI->hasOneUse())

